// Build the exact raw body and its HMAC-SHA256 signature. The TOWER hook
// verifies X-Wings-Signature over the RAW body (same contract as the whatsapp
// and revalidate hooks), so we must sign the literal bytes we send — never a
// re-serialized object. An empty JSON object means "scan all open journeys";
// set JOURNEY_ADVANCE_LIMIT to cap the batch, or JOURNEY_ADVANCE_JOURNEY_ID to
// target one journey.
const crypto = require('crypto');
const secret = $env.JOURNEY_ADVANCE_SECRET;
if (!secret) {
  throw new Error('JOURNEY_ADVANCE_SECRET env var is not set on the n8n instance.');
}

const payload = {};
if ($env.JOURNEY_ADVANCE_JOURNEY_ID) payload.journeyId = $env.JOURNEY_ADVANCE_JOURNEY_ID;
if ($env.JOURNEY_ADVANCE_LIMIT) payload.limit = Number($env.JOURNEY_ADVANCE_LIMIT);

const rawBody = JSON.stringify(payload);
const sig = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody, 'utf8').digest('hex');

return [{ json: { rawBody, signature: sig } }];
